detailed_optimizations.code_changes:
将k循环移到最外层，并对i和j循环进行分块，以提高数据局部性。

// 优化后代码
#pragma scop
for (k = 0; k < _PB_M; k++) {
  for (i = 0; i < _PB_N; i++) {
    for (j = 0; j <= i; j++) {
      if (k == 0) C[i][j] *= beta;
      C[i][j] += A[j][k]*alpha*B[i][k] + B[j][k]*alpha*A[i][k];
    }
  }
}
#pragma endscop

1) 将A和B矩阵按列优先存储或转置为列主序；2) 对C矩阵使用分块存储格式。

// 修改数据结构
typedef struct {
  DATA_TYPE* data;
  int block_size;
} BlockedMatrix;

// 修改访问模式
C[i][j] -> C_blocked[block_i][block_j][local_i][local_j]

1) 使用编译器指令强制向量化；2) 手动展开内层循环。

#pragma omp simd
for (j = 0; j <= i-3; j+=4) {
  C[i][j] += A[j][k]*alpha*B[i][k] + B[j][k]*alpha*A[i][k];
  C[i][j+1] += A[j+1][k]*alpha*B[i][k] + B[j+1][k]*alpha*A[i][k];
  // ...
}

